var _ IAudioPolicyService = (*audioPolicyServiceStubWrapper)(nil)

// NewAudioPolicyServiceStub creates a server-side IAudioPolicyService wrapping the given
// server implementation. The returned value satisfies IAudioPolicyService
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewAudioPolicyServiceStub(
	impl IAudioPolicyServiceServer,
) IAudioPolicyService {
	wrapper := &audioPolicyServiceStubWrapper{impl: impl}
	stub := &AudioPolicyServiceStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
